def _load_pixmap_from_base64(b64_data: str) -> QPixmap:
    byte_array = QByteArray.fromBase64(b64_data.encode('utf-8'))
    pixmap = QPixmap()
    pixmap.loadFromData(byte_array)
    return pixmap

def get_pixmap(name: str, size: int = None, width: int = None, height: int = None) -> QPixmap:
    b64_data = ICONS_MAP.get(name, ICON_FOLDER)
    pixmap = _load_pixmap_from_base64(b64_data)
    
    if pixmap.isNull():
        return pixmap
    
    if width and height:
        pixmap = pixmap.scaled(
            width, height,
            Qt.AspectRatioMode.KeepAspectRatio,
            Qt.TransformationMode.SmoothTransformation
        )
    elif size:
        pixmap = pixmap.scaled(
            size, size,
            Qt.AspectRatioMode.KeepAspectRatio,
            Qt.TransformationMode.SmoothTransformation
        )
    
    return pixmap

def get_icon(name: str, size: int = None, width: int = None, height: int = None) -> QIcon:
    return QIcon(get_pixmap(name, size, width, height))
